        MOD = 10**9 + 7
        suf = [[0]*(cols+1) for _ in range(rows+1)]
        for r in range(rows-1, -1, -1):
            for c in range(cols-1, -1, -1):
                suf[r][c] = (1 if pizza[r][c]=='A' else 0) + suf[r+1][c] + suf[r][c+1] - suf[r+1][c+1]
        def apples(r1, c1, r2, c2):
            return suf[r1][c1] - suf[r2+1][c1] - suf[r1][c2+1] + suf[r2+1][c2+1]
        dp = [[[0]*cols for _ in range(rows)] for _ in range(k+1)]
        for r in range(rows):
            for c in range(cols):
                dp[1][r][c] = 1 if apples(r, c, rows-1, cols-1) > 0 else 0
        for t in range(2, k+1):
            for r in range(rows):
                for c in range(cols):
                    if apples(r, c, rows-1, cols-1) == 0:
                        continue
                    ans = 0
                    for i in range(r, rows-1):
                        if apples(r, c, i, cols-1) > 0:
                            ans = (ans + dp[t-1][i+1][c]) % MOD
                    for j in range(c, cols-1):
                        if apples(r, c, rows-1, j) > 0:
                            ans = (ans + dp[t-1][r][j+1]) % MOD
                    dp[t][r][c] = ans
        return dp[k][0][0]

