var ways = function(pizza, k) {
    const rows = pizza.length, cols = pizza[0].length;
    const MOD = 1000000007n;
    const suf = Array.from({length: rows+1}, () => new Array(cols+1).fill(0n));
    for (let r = rows-1; r >= 0; r--) {
        for (let c = cols-1; c >= 0; c--) {
            suf[r][c] = (pizza[r][c] === 'A' ? 1n : 0n) + suf[r+1][c] + suf[r][c+1] - suf[r+1][c+1];
        }
    }
    function apples(r1, c1, r2, c2) {
        return suf[r1][c1] - suf[r2+1][c1] - suf[r1][c2+1] + suf[r2+1][c2+1];
    }
    const dp = Array.from({length: k+1}, () =>
        Array.from({length: rows}, () => new Array(cols).fill(0n))
    );
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            dp[1][r][c] = apples(r, c, rows-1, cols-1) > 0n ? 1n : 0n;
        }
    }
    for (let t = 2; t <= k; t++) {
        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                if (apples(r, c, rows-1, cols-1) <= 0n) continue;
                let ans = 0n;
                for (let i = r; i < rows-1; i++) {
                    if (apples(r, c, i, cols-1) > 0n) ans = (ans + dp[t-1][i+1][c]) % MOD;
                }
                for (let j = c; j < cols-1; j++) {
                    if (apples(r, c, rows-1, j) > 0n) ans = (ans + dp[t-1][r][j+1]) % MOD;
                }
                dp[t][r][c] = ans;
            }
        }
    }
    return Number(dp[k][0][0]);
};
